            ver = obj["ver"] if "ver" in obj else obj.get("version", obj.get("v"))
            payload = obj["payload"] if "payload" in obj else obj.get("data", obj.get("body"))
            checksum = obj["checksum"] if "checksum" in obj else obj.get("chk", obj.get("csum"))
            if ver is None or payload is None or checksum is None:
                raise ValueError
            if not isinstance(payload, str):
                raise ValueError
            return {"ver": _to_int(ver), "payload": payload, "checksum": _to_int(checksum)}
    except Exception:
        pass

