        r"\s*(?:FLUXON|FLX)?\s*[\|\:]\s*(?:v(?:er(?:sion)?)?\s*=?\s*)?([0-9]+)\s*[\|\:]\s*(.*?)\s*[\|\:]\s*(?:checksum|chk|csum)?\s*=?\s*([0-9]+)\s*",
        s,
        re.IGNORECASE | re.DOTALL,
    )
    if m:
        return {"ver": int(m.group(1)), "payload": m.group(2), "checksum": int(m.group(3))}

