            raise ValueError
        return {"ver": _to_int(ver_s), "payload": payload, "checksum": _to_int(checksum_s)}

    raise ValueError


def _checksum(payload: str, ver: int) -> int:
    return (sum(ord(ch) for ch in payload) + ver) % 256


