def _solve_parse_fluxon_packet(packet: str) -> dict[str, Any]:
    parser = globals().get("parse_fluxon_packet")
    if callable(parser):
        return parser(packet)

    pattern = globals().get("_PACKET_PATTERN")
    if pattern is not None:
        match = pattern.match(packet)
        if not match:
            raise ValueError("invalid packet format")
        groups = match.groupdict()
        version = int(groups["version"])
        payload = groups["payload"]
        return {
            "version": version,
            "channel": groups["channel"],
            "payload": payload,
            "checksum": int(groups["checksum"]),
            "tokens": payload.split("-") if payload else [],
        }

    parser = globals().get("parse_fluxon_packet_wrong_key")
    if callable(parser):
        return parser(packet)

    patterns = (
        r"^(?:FLUXON|Fluxon|fluxon)?[:|/,-]?[vV]?(?P<version>\d+)[:|/,-]+(?P<channel>[A-Za-z]+)[:|/,-]+(?P<payload>[A-Za-z0-9]*(?:-[A-Za-z0-9]+)*)[:|/,-]+(?P<checksum>\d+)$",
        r"^[A-Za-z_]*[vV]?(?P<version>\d+)\[(?P<channel>[A-Za-z]+)\](?::|=)(?P<payload>[A-Za-z0-9]*(?:-[A-Za-z0-9]+)*)(?::|#)(?P<checksum>\d+)$",
        r"^[A-Za-z_]*[vV]?(?P<version>\d+)\((?P<channel>[A-Za-z]+)\)(?::|=)(?P<payload>[A-Za-z0-9]*(?:-[A-Za-z0-9]+)*)(?::|#)(?P<checksum>\d+)$",
    )
    for pat in patterns:
        match = re.match(pat, packet)
        if match:
            groups = match.groupdict()
            payload = groups["payload"]
            return {
                "version": int(groups["version"]),
                "channel": groups["channel"],
                "payload": payload,
                "checksum": int(groups["checksum"]),
                "tokens": payload.split("-") if payload else [],
            }

    parts = re.findall(r"[A-Za-z0-9]+(?:-[A-Za-z0-9]+)*", packet)
    if len(parts) >= 4 and parts[-1].isdigit():
        checksum = int(parts[-1])
        payload = parts[-2]
        channel = parts[-3]
        version_part = parts[-4]
        version_match = re.search(r"\d+", version_part)
        if version_match and re.fullmatch(r"[A-Za-z]+", channel):
            return {
                "version": int(version_match.group(0)),
                "channel": channel,
                "payload": payload,
                "checksum": checksum,
                "tokens": payload.split("-") if payload else [],
            }

    raise ValueError("invalid packet format")


def _solve_compute_fluxon_checksum(payload: str, version: int) -> int:
    func = globals().get("compute_fluxon_checksum")
    if callable(func):
        return func(payload, version)

    total = sum(ord(ch) for ch in payload) + version
    candidates = [
        total % 97,
        total % 100,
        total % 101,
        total % 127,
        total % 251,
        total % 255,
        total % 256,
        total,
    ]
    return candidates[0]


