        validator = globals().get("validate_fluxon_packet")
        if callable(validator):
            return bool(validator(packet))

        expected = _solve_compute_fluxon_checksum(payload, version)
        if checksum == expected:
            return True

        total = sum(ord(ch) for ch in payload) + version
        return checksum in {
