        try:
            data = json.loads(text)
        except Exception:
            data = ast.literal_eval(text)
        payload = str(data.get("payload", ""))
        return {
            "version": int(data["version"]),
            "channel": data.get("channel", ""),
            "payload": payload,
            "tokens": list(data.get("tokens") or (payload.split("-") if payload else [])),
            "checksum": data.get("checksum"),
        }

    parts = [p.strip() for p in re.split(r"[|;,]", text) if p.strip()]
    kv: dict[str, str] = {}

    for part in parts:
        if "=" in part:
            k, v = part.split("=", 1)
            kv[k.strip().lower()] = v.strip()
        elif ":" in part:
            k, v = part.split(":", 1)
            if re.fullmatch(r"[A-Za-z_][A-Za-z0-9_ -]*", k.strip()):
                kv[k.strip().lower().replace(" ", "_")] = v.strip()

    if kv and any(k in kv for k in ("version", "ver", "v")):
        version_value = kv.get("version", kv.get("ver", kv.get("v")))
        version_match = re.search(r"\d+", str(version_value))
        if not version_match:
            raise ValueError("Invalid packet version")
        payload = kv.get("payload", kv.get("data", kv.get("tokens", ""))).strip()
        if payload.startswith("[") and payload.endswith("]"):
            try:
                parsed_tokens = ast.literal_eval(payload)
                payload = "-".join(str(t) for t in parsed_tokens)
            except Exception:
                pass
        return {
            "version": int(version_match.group()),
            "channel": kv.get("channel", kv.get("chan", kv.get("ch", ""))),
