    if not payload:
        return 0
    return sum(_token_value(t) for t in payload.split("-") if t)


def _extract_int(value: Any) -> int | None:
    if value is None:
        return None
    if isinstance(value, int):
        return value
    m = re.search(r"-?\d+", str(value))
    return int(m.group(0)) if m else None


def _parse_mapping(obj: dict[str, Any]) -> dict[str, Any]:
    lower = {str(k).lower(): v for k, v in obj.items()}

    version = None
    for key in ("version", "ver", "v"):
        if key in lower:
            version = _extract_int(lower[key])
            break

    channel = ""
    for key in ("channel", "chan", "ch", "c"):
        if key in lower:
            channel = str(lower[key])
            break

    payload = None
    for key in ("payload", "data", "body", "p"):
        if key in lower:
            payload = str(lower[key])
            break

    tokens = None
    if "tokens" in lower and isinstance(lower["tokens"], list):
        tokens = [str(t) for t in lower["tokens"]]

    if payload is None:
        if tokens is not None:
            payload = "-".join(tokens)
        else:
            payload = ""

    if tokens is None:
        tokens = payload.split("-") if payload else []

    checksum = None
    for key in ("checksum", "check", "sum", "crc"):
        if key in lower:
            checksum = _extract_int(lower[key])
            break

    if version is None:
        raise ValueError("Missing version")

    return {
        "version": version,
        "channel": channel,
        "payload": payload,
        "tokens": tokens,
        "checksum": checksum,
    }


