        channel = channel.lower()
        if channel == "alpha":
            return raw / 100.0
        if channel == "beta":
            return raw / 10.0
        return raw

    def extract_tokens(value: Any) -> list[str]:
        if value is None:
            return []
        if isinstance(value, (list, tuple)):
            tokens = []
            for item in value:
                tokens.extend(extract_tokens(item))
            return tokens
        return re.findall(r"\b[ABCDEFG][0-9]\b", str(value))

